+			const cleanResponse = stripRaw(response);
+
+			entries.push({
+				type: "complete",
+				request,
+				response: cleanResponse,
+			});
+
+			return response;
+		},
+		stream: async function* (request: Request): AsyncIterable<StreamEvent> {
+			const events: StreamEvent[] = [];
+			for await (const event of realAdapter.stream(request)) {
+				events.push(event);
+				yield event;
+			}
+
+			entries.push({
+				type: "stream",
+				request,
+				events,
+			});
+		},
